namespace sv_766cb2378e57446eb8b3f884ddee1610.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>
            {
                new() { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
                new() { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
                new() { Id = _nextId++, Message = "New feature available: dark mode.", Timestamp = DateTime.UtcNow.AddMinutes(-1) },
            };
            return Task.FromResult(items);
        }
    }

    public Task<List<NotificationItem>> CheckForNewAsync(int afterId)
    {
        lock (_lock)
        {
            var items = new List<NotificationItem>
            {
                new() { Id = _nextId++, Message = $"New alert at {DateTime.UtcNow:HH:mm:ss}", Timestamp = DateTime.UtcNow }
            };
            return Task.FromResult(items);
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationService NotificationSvc

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading notifications...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<NotificationItem>? notifications { get; set; }

    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch when state wasn't restored from prerender
        notifications ??= await NotificationSvc.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs in the interactive render, never during prerender
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var lastId = notifications?.Count > 0 ? notifications.Max(n => n.Id) : 0;
                var newItems = await NotificationSvc.CheckForNewAsync(lastId);

                if (newItems.Count > 0)
                {
                    notifications ??= new();
                    notifications.AddRange(newItems);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

